import { NativeModules } from 'react-native';
const { RNIoTModule } = NativeModules; // Assuming that you have bridged your native code to a module called "RNIoTModule"

class NetworkingService {
    constructor(baseURL) {
        this.baseURL = baseURL;
    }

    async getData(endpoint, headers={}) {
        const url = `${this.baseURL}${endpoint}`;
        try {
            let response = await fetch(url, { method: 'GET', headers: headers });
            
            if (response.ok) {
                return await response.json();
            } else {
                throw new Error('Network response was not ok');
            }
        } catch(error) {
            console.warn("There has been a problem with your fetch operation: ", error);
        }
    }

    postData(endpoint, data, headers={}) {
        const url = `${this.baseURL}${endpoint}`;
        
        return fetch(url, {
            method: 'POST',
            headers: headers,
            body: JSON.stringify(data) 
        })
        .then(response => response.json())
        .catch((error) => console.warn("There has been a problem with your fetch operation: ", error));
    }
    
    // Use WebSocket for IoT communication
    connectIoTDevice() {
        try {
            const ws = new WebSocket('ws://192.168.x.x');
            
            ws.onmessage = (event) => console.log(`Received data: ${event.data}`); 

            ws.onerror = (error) => console.warn("WebSocket encountered error: ", error);

            ws.onopen = () => RNIoTModule.initIoTDevice(); // You have to bridge this method from your native code
        } catch(exception) {
          console.warn('Failed to connect with WebSocket', exception);  
        }   
    }
}

// Instantiate a new NetworkingService using the API's URL
